class Solution:
    def maxDistance(self, s, k):
        n = len(s)
        best = 0
        moves = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
        dirs = list(moves.values())
        def solve(i, x, y, changes_left):
            nonlocal best
            dist = abs(x) + abs(y)
            if dist > best:
                best = dist
            if i == n:
                return
            dx, dy = moves[s[i]]
            solve(i + 1, x + dx, y + dy, changes_left)
            if changes_left > 0:
                for ddx, ddy in dirs:
                    if (ddx, ddy) != (dx, dy):
                        solve(i + 1, x + ddx, y + ddy, changes_left - 1)
        solve(0, 0, 0, min(k, n))
        return best

