class Solution:
    def maxDistance(self, s, k):
        def best_for(plus_set):
            cur = 0
            used = 0
            best = 0
            for ch in s:
                val = 1 if ch in plus_set else -1
                if val == -1 and used < k:
                    val = 1
                    used += 1
                cur += val
                if cur > best:
                    best = cur
            return best
        combos = [set('NE'), set('SW'), set('WN'), set('ES')]
        return max(best_for(c) for c in combos)

