var maxDistance = function(s, k) {
    function bestFor(plusSet) {
        let cur = 0, used = 0, best = 0;
        for (const ch of s) {
            let val = plusSet.has(ch) ? 1 : -1;
            if (val === -1 && used < k) { val = 1; used++; }
            cur += val;
            if (cur > best) best = cur;
        }
        return best;
    }
    const combos = [new Set(['N', 'E']), new Set(['S', 'W']), new Set(['W', 'N']), new Set(['E', 'S'])];
    let best = 0;
    for (const c of combos) {
        const v = bestFor(c);
        if (v > best) best = v;
    }
    return best;
};
